zoom = 0.78752;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.033;
cx = 0.5;
cy = 0.5;
vol=(bass+mid+treb)*0.25;;
vol=vol*vol;;
vol2=(bass_att+mid_att+treb_att)*0.25;;
vol2=vol2*vol2;;
q2=vol2;;
mtime=mtime+vol*0.01;;
