//can be buggy; if doesn't work, run init code.;
//--------------------------------------;
//Fed's beat code:;
//;
//br - beat rate;;
//bt,bt2 - beat times;;
//spika - beat detector, power of the beat;;
//count - beat counter;;
//++++++++++++++++++++++++++++++++++++++;
//TRESH - power of treble to detect beat;;
//BASH - power of bass to detect beat;;
//beat detector works only if both of them;
//are less then treb & bass!;
//++++++++++++++++++++++++++++++++++++++;
//abt - summ of all beatrates;;
//Increases if no beat.;
//mvol - middle volume;;
//mba - middle bass;;
//mtr - middle treb;;
//pret - preset time;;
//clr - amount of seconds to recalculate volumes.;
//--------------------------------------;
pret=time-st;;
avol=avol+(bass+mid+treb)/3;;
aba=aba+bass;;
mba=aba/pret/fps;;
atr=atr+treb;;
mtr=atr/pret/fps;;
mvol=avol/pret/fps;;
TRESH=mtr+0.1;;
BASH=mba+0.1;;
clr=50;//----------HERE!!!!!! in seconds.;
abass=bass_att*0.4+abass;;
bt=time*((spika) > (0))+bt*((spika) == (0));;
spika=((treb_att) > (TRESH))*treb+((bass_att) > (BASH))*bass;;
spik=spik+spika*0.4;;
bt2=time*((spika) > (0))+bt*((spika) == (0));;
count=count+((bt2-bt) > (0));;
abt=max(((br) < (10)),((br) == (10)))*(abt+if(bt2-bt, bt2-bt, 1/fps))+((br) > (10));;
br=abt/count;;
dx=dx-cos(abass)*br*0.02+sin(spik)/br*0.02;;
dy=dy-sin(abass)*br*0.02+cos(spik)/br*0.02;;
sx=sx+sin(abass)*dx*2;;
sy=sy-cos(spik)*dy*2;;
ib_a=pow(spika/5,5);  //<--That's how we use it.;
//debugging;
calc=((pret) < (clr));;
abass=((abass) < (9000))*abass;;
avol=if(calc,avol,(bass+mid+treb)/3);;
st=if(calc,st,time-1);;
aba=if(calc,aba,bass);;
atr=if(calc,atr,treb);;
abt=((pret) > (0.2))*abt+((pret) < (0.2))*0.5;;
//fun;
afps=(fps+afps)/2;;
zoom=zoom-(fps/afps-1)*90;;
q4=int(pret/br)%2;;
q5=((spika) > (0));;
